  # Build sentences for each subject, merging multiple facts into a fluent clause
      subject_sentences: list[str] = []
      for subj, clauses in subject_map.items():
          if len(clauses) == 1:
              # Single clause – use it as‑is
              subject_sentences.append(clauses[0])
          else:
              # Keep the first clause intact, turn the rest into relative fragments
              first_clause = clauses[0]
              rest_fragments = []
              for clause in clauses[1:]:
                  if clause.startswith(subj):
                      frag = clause[len(subj):].lstrip()
                  else:
                      frag = clause
                  rest_fragments.append(frag)
              # Join the rest with commas and an 'and' before the final fragment
              if len(rest_fragments) == 1:
                  combined = rest_fragments[0]
              else:
                  combined = ", ".join(rest_fragments[:-1]) + " and " + rest_fragments[-1]
              # Attach the combined fragment to the first clause
              subject_sentences.append(f"{first_clause}, {combined}")
